class Solution {
public:
    int minAddToMakeValid(string s) {
        int open = 0, close = 0;
        for (char c : s) {
            if (c == '(') open++;
            else if (c == ')') {
                if (open > 0) open--;
                else close++;
            }
        }
        return open + close;
    }
};
```

efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
